from claude_agent_sdk import tool, create_sdk_mcp_server, ClaudeAgentOptions

@tool("check_order", "Проверяет статус заказа по номеру", {"order_id": str})
async def check_order(args):
    status = db_lookup(args["order_id"])  # твоя логика
    return {"content": [{"type": "text", "text": f"Статус: {status}"}]}

server = create_sdk_mcp_server(name="shop", version="1.0.0", tools=[check_order])

options = ClaudeAgentOptions(
    mcp_servers={"shop": server},
    allowed_tools=["mcp__shop__check_order", "Read"],
)

